const body = $input.first().json.body || $input.first().json;

const event_id = body.event_id;
const payload = body.payload || {};

return [{
  json: {
    event_id,
    project_number: payload.project_number,
    doc_type: payload.doc_type,
    files: payload.files || [],
    file_count: payload.file_count || 0,
    source_event_id: payload.source_event_id,
    step_key: `M4_10_PARSE:${event_id}`
  }
}];

const extractData = $('📋 Extract Data').first().json;
const projectId = $('🔎 Lookup Project').first().json.id;

if (!projectId) {
  throw new Error(`Project not found: ${extractData.project_number}`);
}

// Bei MAGICPLAN alle Files nehmen (Filename geht bei Superchat-Download verloren)
// Sonst nur CSV files
const csvFiles = extractData.doc_type === 'MAGICPLAN'
  ? extractData.files
  : extractData.files.filter(f => 
      f.mime_type === 'text/csv' || 
      f.name?.endsWith('.csv') ||
      f.storage_path?.endsWith('.csv')
    );

if (csvFiles.length === 0) {
  throw new Error('No CSV files found in attachments');
}

return csvFiles.map(file => ({
  json: {
    ...file,
    project_id: projectId,
    project_number: extractData.project_number,
    event_id: extractData.event_id,
    step_key: extractData.step_key,
    doc_type: extractData.doc_type
  }
}));

// Im Parse CSV Node - Add filter for valid sections
const csvContent = $input.first().json.data;
const prevData = $('🔀 Filter CSV Files').first().json;

const lines = csvContent.split('\n');

// Finde "ATTRIBUTE DER RÄUME" Section
let startIndex = -1;
let headerLine = null;

for (let i = 0; i < lines.length; i++) {
  if (lines[i].includes('ATTRIBUTE DER RÄUME')) {
    startIndex = i;
    headerLine = lines[i];
    break;
  }
}

if (startIndex === -1) {
  throw new Error('Section ATTRIBUTE DER RÄUME not found in CSV');
}

// Parse Header für Spalten-Mapping
const headers = headerLine.split(',');

const colMap = {
  floor_area: headers.findIndex(h => h.includes('Boden Oberfläche')),
  volume: headers.findIndex(h => h.includes('Volumen')),
  perimeter: headers.findIndex(h => h.includes('Bodenumfang')),
  ceiling_perimeter: headers.findIndex(h => h.includes('Deckenumfang')),
  wall_with_openings: headers.findIndex(h => h.includes('Wandfläche mit Öffnungen')),
  wall_without_openings: headers.findIndex(h => h.includes('Wandfläche ohne Öffnungen')),
  door_area: headers.findIndex(h => h.includes('Türflächen')),
  window_area: headers.findIndex(h => h.includes('Fensteroberflächen')),
  room_height: headers.findIndex(h => h.includes('Raumhöhe'))
};

// Invalid floor names to skip
const INVALID_FLOORS = ['ANZAHL DER OBJEKTE', 'SYMBOLE', 'NOTIZEN', 'ZUSAMMENFASSUNG'];

// Parse Rooms
const rooms = [];
let currentFloor = 'Erdgeschoss';
let skipSection = false;

for (let i = startIndex + 1; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line || line.startsWith(',')) continue;

  const cols = line.split(',');
  const firstCol = cols[0]?.trim();

  if (!firstCol) continue;

  // Check if this is a section we should skip
  if (INVALID_FLOORS.some(inv => firstCol.toUpperCase().includes(inv.toUpperCase()))) {
    skipSection = true;
    continue;
  }

  // Check if this is a floor header (only has first column, rest empty)
  const hasData = cols.slice(1, 5).some(c => c && c.trim() && !isNaN(parseFloat(c.trim())));

  if (!hasData && firstCol) {
    // This is a floor name - check if valid
    if (!INVALID_FLOORS.some(inv => firstCol.toUpperCase().includes(inv.toUpperCase()))) {
      currentFloor = firstCol;
      skipSection = false;
    }
    continue;
  }

  // Skip if we're in an invalid section
  if (skipSection) continue;

  // This is a room row
  const parseNum = (idx) => {
    if (idx < 0 || !cols[idx]) return null;
    const val = cols[idx].trim().replace(' m', '').replace(',', '.');
    const num = parseFloat(val);
    return isNaN(num) ? null : num;
  };

  rooms.push({
    project_id: prevData.project_id,
    floor_name: currentFloor,
    room_name: firstCol,
    floor_area_m2: parseNum(colMap.floor_area),
    volume_m3: parseNum(colMap.volume),
    perimeter_m: parseNum(colMap.perimeter),
    ceiling_perimeter_m: parseNum(colMap.ceiling_perimeter),
    wall_area_with_openings_m2: parseNum(colMap.wall_with_openings),
    wall_area_m2: parseNum(colMap.wall_without_openings),
    door_area_m2: parseNum(colMap.door_area),
    window_area_m2: parseNum(colMap.window_area),
    room_height_m: parseNum(colMap.room_height),
    source_file: prevData.storage_path,
    source_event_id: prevData.event_id
  });
}

if (rooms.length === 0) {
  throw new Error('No rooms found in CSV');
}

return rooms.map(room => ({ json: { ...room, ...prevData } }));

const allItems = $input.all();
const firstItem = $('🔬 Parse CSV').first().json;

const roomCount = allItems.length;
const roomNames = $('🔬 Parse CSV').all().map(i => i.json.room_name);

return [{
  json: {
    project_id: firstItem.project_id,
    project_number: firstItem.project_number,
    event_id: firstItem.event_id,
    step_key: firstItem.step_key,
    room_count: roomCount,
    rooms: roomNames,
    source_file: firstItem.source_file
  }
}];

